#include <Wire.h>
#include <SPI.h>
extern bool astar_next_cell(int,int,int,int,uint8_t,int*,int*);
int cx=0,cy=0,gx=7,gy=7;
void ir_setup(){for(int i=A0;i<=A3;i++)pinMode(i,INPUT);}
uint8_t ir_walls(){
  uint8_t w=0;
  for(int d=0;d<4;d++)if(analogRead(A0+d)<400)w|=(1<<d);
  return w;}
void drive_setup(){int pp[]={5,6,7,8};for(int p:pp)pinMode(p,OUTPUT);}
void drive_forward(){analogWrite(5,180);analogWrite(6,0);analogWrite(7,180);analogWrite(8,0);delay(500);drive_stop();}
void drive_stop(){int pp[]={5,6,7,8};for(int p:pp)analogWrite(p,0);}
void lcd_show(){
  Serial.print("[");Serial.print(cx);Serial.print(",");Serial.print(cy);
  Serial.print("]>[");Serial.print(gx);Serial.print(",");Serial.println(gy);}
void bt_check(){
  if(Serial1.available()>2){
    char b[16];int n=Serial1.readBytesUntil('\n',b,15);b[n]=0;
    if(b[0]=='G')sscanf(b+2,"%d,%d",&gx,&gy);}}
void fault_check(){
  if(cx<0||cx>7||cy<0||cy>7){
    drive_stop();Serial.println("FAULT:OOB");while(1);}}
void setup(){
  Serial.begin(115200);Serial1.begin(9600);
  ir_setup();drive_setup();Wire.begin();}
void loop(){
  bt_check();fault_check();
  if(cx==gx&&cy==gy){drive_stop();Serial.println("GOAL");delay(2000);return;}
  uint8_t w=ir_walls();int nx,ny;
  if(astar_next_cell(gx,gy,cx,cy,w,&nx,&ny)){
    drive_forward();cx=nx;cy=ny;}
  lcd_show();delay(100);}
